#include "hirct/Target/GenVerify.h"
#include "hirct/Analysis/IRAnalysis.h"

#include <cctype>
#include <cerrno>
#include <cstring>
#include <fstream>
#include <iostream>
#include <sys/stat.h>

namespace hirct {

namespace {

static constexpr const char *AUTO_GENERATED_HEADER =
    "// AUTO-GENERATED by hirct-gen \xe2\x80\x94 DO NOT EDIT\n";

std::string to_lower(const std::string &s) {
  std::string r;
  r.reserve(s.size());
  for (char c : s) {
    r += static_cast<char>(std::tolower(static_cast<unsigned char>(c)));
  }
  return r;
}

bool ends_with(const std::string &s, const std::string &suffix) {
  return s.size() >= suffix.size() &&
         s.compare(s.size() - suffix.size(), suffix.size(), suffix) == 0;
}

bool starts_with(const std::string &s, const std::string &prefix) {
  return s.size() >= prefix.size() && s.compare(0, prefix.size(), prefix) == 0;
}

} // namespace

GenVerify::GenVerify(circt::hw::HWModuleOp hw_module)
    : hw_module_(hw_module) {}

std::string GenVerify::cpp_type_for_width(int width) const {
  if (width == 1)
    return "bool";
  if (width <= 8)
    return "uint8_t";
  if (width <= 16)
    return "uint16_t";
  if (width <= 32)
    return "uint32_t";
  if (width <= 64)
    return "uint64_t";
  return "";
}

std::string GenVerify::random_expr_for_width(int width) const {
  if (width <= 1) {
    return "(rng() & 1)";
  }
  if (width <= 31) {
    return "(static_cast<uint32_t>(rng()) & ((1u << " + std::to_string(width) +
           ") - 1u))";
  }
  if (width == 32) {
    return "(static_cast<uint32_t>(rng()))";
  }
  if (width <= 63) {
    return "(rng() & ((1ULL << " + std::to_string(width) + ") - 1ULL))";
  }
  return "(rng())";
}

bool GenVerify::emit(const std::string &output_dir) {
  struct SimplePort {
    std::string name;
    int width;
  };
  std::string module;
  std::vector<SimplePort> in_ports, out_ports;
  std::string clock_name, reset_name;

  module = hw_module_.getSymName().str();
  for (const auto &p : hirct::get_input_ports(hw_module_))
    in_ports.push_back({p.name, static_cast<int>(p.width ? p.width : 1)});
  for (const auto &p : hirct::get_output_ports(hw_module_))
    out_ports.push_back({p.name, static_cast<int>(p.width ? p.width : 1)});
  for (const auto &p : hirct::get_ports(hw_module_)) {
    if (clock_name.empty() && hirct::is_clock_port(p.name))
      clock_name = p.name;
    if (reset_name.empty() && hirct::is_reset_port(p.name))
      reset_name = p.name;
  }

  if (out_ports.empty()) {
    std::cerr << "GenVerify: no output ports to compare\n";
    return false;
  }

  std::string verify_dir = output_dir + "/verify";
  if (mkdir(verify_dir.c_str(), 0755) != 0 && errno != EEXIST) {
    std::cerr << "GenVerify: cannot create directory: " << verify_dir << ": "
              << strerror(errno) << "\n";
    return false;
  }

  std::string path = verify_dir + "/verify_" + module + ".cpp";

  std::ofstream ofs(path);
  if (!ofs) {
    std::cerr << "GenVerify: cannot open " << path << "\n";
    return false;
  }

  ofs << AUTO_GENERATED_HEADER;
  ofs << "#include <cstdlib>\n";
  ofs << "#include <cstdint>\n";
  ofs << "#include <iostream>\n";
  ofs << "#include <random>\n";
  ofs << "#include <string>\n";
  ofs << "#include <verilated.h>\n";
  ofs << "#include <verilated_vcd_c.h>\n";
  ofs << "#include \"V" << module << ".h\"\n";
  ofs << "#include \"../cmodel/" << module << ".h\"\n\n";
  ofs << "int main(int argc, char **argv) {\n";
  ofs << "  int cycles = 100;\n";
  ofs << "  int seed = 1;\n";
  ofs << "  if (argc > 1) cycles = std::atoi(argv[1]);\n";
  ofs << "  if (argc > 2) seed = std::atoi(argv[2]);\n";
  ofs << "  if (cycles <= 0) cycles = 1;\n";
  ofs << "  std::mt19937_64 rng(seed);\n";
  ofs << "  Verilated::randReset(2);\n";
  ofs << "  V" << module << " rtl;\n";
  ofs << "  " << module << " model;\n";
  ofs << "  model.do_reset();\n";
  ofs << "  VerilatedVcdC* vcd = nullptr;\n";
  ofs << "  if (argc > 3 && std::string(argv[3]) == \"--dump-vcd\") {\n";
  ofs << "    Verilated::traceEverOn(true);\n";
  ofs << "    vcd = new VerilatedVcdC;\n";
  ofs << "    rtl.trace(vcd, 99);\n";
  ofs << "    std::string vcd_file = std::string(\"debug_\") + argv[2] + "
         "\".vcd\";\n";
  ofs << "    vcd->open(vcd_file.c_str());\n";
  ofs << "  }\n";

  if (!clock_name.empty()) {
    ofs << "  rtl." << clock_name << " = 0;\n";
  }
  if (!reset_name.empty()) {
    std::string lower = to_lower(reset_name);
    bool active_low = ends_with(lower, "_n");
    ofs << "  rtl." << reset_name << " = " << (active_low ? "0" : "1") << ";\n";
    ofs << "  rtl.eval();\n";
    if (!clock_name.empty()) {
      ofs << "  rtl." << clock_name << " = 1;\n";
      ofs << "  rtl.eval();\n";
      ofs << "  rtl." << clock_name << " = 0;\n";
    }
    ofs << "  rtl." << reset_name << " = " << (active_low ? "1" : "0") << ";\n";
  }

  ofs << "  int pass = 0;\n";
  ofs << "  int fail = 0;\n";
  ofs << "  for (int cyc = 0; cyc < cycles; ++cyc) {\n";

  for (const auto &p : in_ports) {
    std::string lower_name = to_lower(p.name);
    if (p.name == clock_name || p.name == reset_name)
      continue;
    std::string ctype = cpp_type_for_width(p.width);
    if (ctype.empty()) {
      std::cerr << "GenVerify: unsupported input width " << p.width << " for "
                << p.name << "\n";
      return false;
    }
    ofs << "    " << ctype << " in_" << p.name << " = static_cast<" << ctype
        << ">(" << random_expr_for_width(p.width) << ");\n";
    ofs << "    rtl." << p.name << " = in_" << p.name << ";\n";
    ofs << "    model." << p.name << " = in_" << p.name << ";\n";
  }

  if (!clock_name.empty()) {
    ofs << "    rtl." << clock_name << " = 0;\n";
    ofs << "    rtl.eval();\n";
    ofs << "    if (vcd) vcd->dump(cyc * 2);\n";
    ofs << "    rtl." << clock_name << " = 1;\n";
    ofs << "    rtl.eval();\n";
    ofs << "    if (vcd) vcd->dump(cyc * 2 + 1);\n";
    ofs << "    model.step();\n";
  } else {
    ofs << "    rtl.eval();\n";
    ofs << "    if (vcd) vcd->dump(cyc);\n";
    ofs << "    model.eval_comb();\n";
  }

  for (const auto &p : out_ports) {
    ofs << "    if (static_cast<uint64_t>(rtl." << p.name
        << ") != static_cast<uint64_t>(model." << p.name << ")) {\n";
    ofs << "      std::cerr << \"FAIL cycle=\" << cyc << \" seed=\" << seed\n";
    ofs << "                << \" port=" << p.name
        << " rtl=\" << static_cast<uint64_t>(rtl." << p.name
        << ") << \" model=\" << static_cast<uint64_t>(model." << p.name
        << ") << \"\\n\";\n";
    ofs << "      ++fail;\n";
    ofs << "      if (fail >= 10) break;\n";
    ofs << "    }\n";
  }

  ofs << "    if (fail == 0) ++pass;\n";
  ofs << "    if (fail >= 10) break;\n";
  ofs << "  }\n";
  ofs << "  std::cout << (fail ? \"FAIL\" : \"PASS\") << \": \" << pass\n";
  ofs << "            << \" pass, \" << fail << \" fail (seed=\" << seed\n";
  ofs << "            << \", cycles=\" << cycles << \")\\n\";\n";
  ofs << "  if (vcd) { vcd->close(); delete vcd; }\n";
  ofs << "  return fail == 0 ? 0 : 1;\n";
  ofs << "}\n";

  return true;
}

} // namespace hirct
